// Function to get all synonyms for a given verb
vector getSynonyms(string verb)
{
 vector synonyms;
 for (int i = 1; i <= 4; i++) {
 for (int j = 1; j <= 2; j++) {
 char *synset = wn_morphstr(verb.c_str(), VERB, i, j);
 if (synset) {
 int sense = atoi(synset + strlen(synset) - 2);
 if (sense > 0) {
 SynsetPtr syn = findtheinfo_ds(verb.c_str(), VERB, sense, ALLSENSES);
 if (syn) {
 for (int k = 0; k < syn->wcount; k++) {
 string synWord(syn->words[k]);
 transform(synWord.begin(), synWord.end(), synWord.begin(), ::tolower);
 if (synWord != verb) {
 synonyms.push_back(synWord);
 }
 }
 }
 }
 }
 }
 }
 return synonyms;
}
// Function to perform contextual analysis and suggest the most suitable synonym
string suggestSynonym(string verb, string context)
{
 vector synonyms = getSynonyms(verb);
 map freqMap;
 for (auto syn : synonyms) {
 freqMap[syn] = count(context.begin(), context.end(), syn[0]);
 }
 string suggestedSynonym = verb;
 int maxFreq = 0;
 for (auto synFreq : freqMap) {
