```
func classifySentence(_ sentence: String) -> String {
 let words = sentence.components(separatedBy: " ")
 let lastWord = words.last?.lowercased() ?? ""
 let punctuation = sentence.last ?? "."
 if lastWord == "?" {
 return "interrogative"
 } else if punctuation == "." {
 return "declarative"
 } else {
 let verbTags = ["VB", "VBD", "VBG", "VBN", "VBP", "VBZ"]
 let tagger = NSLinguisticTagger(tagSchemes: [.lexicalClass], options: 0)
 tagger.string = sentence

 var verbCount = 0
 var subjectCount = 0

 tagger.enumerateTags(in: NSRange(location: 0, length: sentence.utf16.count), unit: .word, scheme: .lexicalClass) { tag, _, _, _ in
 guard let tag = tag else { return }
 let tagValue = tag.rawValue

 if verbTags.contains(tagValue) {
 verbCount += 1
 } else if tagValue == "NN" || tagValue == "NNS" || tagValue == "NNP" || tagValue == "NNPS" {
 subjectCount += 1
 }
 }

 if verbCount == 1 && subjectCount == 1 {
 return "declarative"
 } else {
 return "interrogative"
 }
 }
}
