import "fmt"
func main() {
 coins := []int{1, 2, 3}
 items := []int{1, 2, 3}
 var min int = 999999999
 for i := 0; i < len(coins); i++ {
 for j := 0; j < len(coins); j++ {
 for k := 0; k < len(coins); k++ {
 if coins[i]+coins[j]+coins[k] == items[0]+items[1]+items[2] {
 count := 0
