#include
#include
using namespace std;
vector sieve(int n){
 vector primes(n+1,true);
 primes[0]=primes[1]=false;
 for(int i=2;i*i<=n;i++){
 if(primes[i]){
 for(int j=i*i;j<=n;j+=i){
